68: public class RouteReifier extends ProcessorReifier<RouteDefinition> {
69: 
70:     private static final Logger LOG = LoggerFactory.getLogger(RouteReifier.class);
71: 
72:     private static final String[] RESERVED_PROPERTIES = new String[] {
73:             Route.ID_PROPERTY, Route.CUSTOM_ID_PROPERTY, Route.PARENT_PROPERTY,
74:             Route.DESCRIPTION_PROPERTY, Route.NOTE_PROPERTY,
75:             Route.GROUP_PROPERTY, Route.NODE_PREFIX_ID_PROPERTY,
76:             Route.REST_PROPERTY, Route.CONFIGURATION_ID_PROPERTY };
77: 
78:     public RouteReifier(CamelContext camelContext, ProcessorDefinition<?> definition) {
79:         super(camelContext, (RouteDefinition) definition);
80:     }
81: 
82:     @Override
83:     public Processor createProcessor() throws Exception {
84:         throw new UnsupportedOperationException("Not implemented for RouteDefinition");
85:     }
86: 
87:     public Route createRoute() {
88:         try {
89:             return doCreateRoute();
90:         } catch (FailedToCreateRouteException e) {
91:             throw e;
92:         } catch (Exception e) {
93:             // location on route is stored on input
94:             ProcessorDefinitionHelper.prepareSourceLocation(definition.getResource(), definition.getInput());
95:             String source = LoggerHelper.getSourceLocationOnly(definition.getInput());
96:             throw new FailedToCreateRouteException(definition.getRouteId(), source, definition.toString(), e);
97:         }
98:     }
99: 
100:     // Implementation methods
101:     // -------------------------------------------------------------------------
102:     protected Route doCreateRoute() throws Exception {
103:         // resolve endpoint
104:         Endpoint endpoint = definition.getInput().getEndpoint();
105:         if (endpoint == null) {
106:             EndpointConsumerResolver def = definition.getInput().getEndpointConsumerBuilder();
107:             if (def != null) {
108:                 endpoint = def.resolve(camelContext);
109:             } else {
110:                 endpoint = resolveEndpoint(definition.getInput().getEndpointUri());
111:             }
112:         }
113: 
114:         // create route
115:         String id = definition.idOrCreate(camelContext.getCamelContextExtension().getContextPlugin(NodeIdFactory.class));
116:         String desc = definition.getDescriptionText();
117:         String note = definition.getNote();
118: 
119:         Route route = PluginHelper.getRouteFactory(camelContext).createRoute(camelContext, definition, id,
120:                 desc, note, endpoint, definition.getResource());
121: 
122:         // configure error handler
123:         route.setErrorHandlerFactory(definition.getErrorHandlerFactory());
124: 
125:         // configure variable
126:         String variable = parseString(definition.getInput().getVariableReceive());
127:         if (variable != null) {
128:             // when using variable we need to turn on original message
129:             route.setAllowUseOriginalMessage(true);
130:         }
131: 
132:         // configure tracing
133:         if (definition.getTrace() != null) {
134:             Boolean isTrace = parseBoolean(definition.getTrace());
135:             if (isTrace != null) {
136:                 route.setTracing(isTrace);
137:                 if (isTrace) {
138:                     LOG.debug("Tracing is enabled on route: {}", definition.getId());
139:                     // tracing is added in the DefaultChannel so we can enable
140:                     // it on the fly
141:                 }
142:             }
143:         }
144: 
145:         // configure message history
146:         if (definition.getMessageHistory() != null) {
147:             Boolean isMessageHistory = parseBoolean(definition.getMessageHistory());
148:             if (isMessageHistory != null) {
149:                 route.setMessageHistory(isMessageHistory);
150:                 if (isMessageHistory) {
151:                     LOG.debug("Message history is enabled on route: {}", definition.getId());
152:                 }
153:             }
154:         }
155: 
156:         // configure Log EIP mask
157:         if (definition.getLogMask() != null) {
158:             Boolean isLogMask = parseBoolean(definition.getLogMask());
159:             if (isLogMask != null) {
160:                 route.setLogMask(isLogMask);
161:                 if (isLogMask) {
162:                     LOG.debug("Security mask for Logging is enabled on route: {}", definition.getId());
163:                 }
164:             }
165:         }
166: 
167:         // configure stream caching
168:         if (definition.getStreamCache() != null) {
169:             Boolean isStreamCache = parseBoolean(definition.getStreamCache());
170:             if (isStreamCache != null) {
171:                 route.setStreamCaching(isStreamCache);
172:                 if (isStreamCache) {
173:                     LOG.debug("StreamCaching is enabled on route: {}", definition.getId());
174:                 }
175:             }
176:         }
177: 
178:         // configure delayer
179:         if (definition.getDelayer() != null) {
180:             Long delayer = parseDuration(definition.getDelayer());
181:             if (delayer != null) {
182:                 route.setDelayer(delayer);
183:                 if (delayer > 0) {
184:                     LOG.debug("Delayer is enabled with: {} ms. on route: {}", delayer, definition.getId());
185:                 } else {
186:                     LOG.debug("Delayer is disabled on route: {}", definition.getId());
187:                 }
188:             }
189:         }
190: 
191:         // configure auto startup
192:         Boolean isAutoStartup = parseBoolean(definition.getAutoStartup());
193: 
194:         // configure startup order
195:         Integer startupOrder = definition.getStartupOrder();
196: 
197:         // configure shutdown
198:         if (definition.getShutdownRoute() != null) {
199:             LOG.debug("Using ShutdownRoute {} on route: {}", definition.getShutdownRoute(), definition.getId());
200:             route.setShutdownRoute(parse(ShutdownRoute.class, definition.getShutdownRoute()));
201:         }
202:         if (definition.getShutdownRunningTask() != null) {
203:             LOG.debug("Using ShutdownRunningTask {} on route: {}", definition.getShutdownRunningTask(), definition.getId());
204:             route.setShutdownRunningTask(parse(ShutdownRunningTask.class, definition.getShutdownRunningTask()));
205:         }
206: 
207:         // should inherit the intercept strategies we have defined
208:         route.getInterceptStrategies().addAll(definition.getInterceptStrategies());
209: 
210:         // notify route context created
211:         for (LifecycleStrategy strategy : camelContext.getLifecycleStrategies()) {
212:             strategy.onRouteContextCreate(route);
213:         }
214: 
215:         // validate route has output processors
216:         if (!hasOutputs(definition.getOutputs(), true)) {
217:             String at = definition.getInput().toString();
218:             Exception cause = new IllegalArgumentException(
219:                     "Route " + definition.getId() + " has no output processors."
220:                                                            + " You need to add outputs to the route such as to(\"log:foo\").");
221:             // location on route is stored on input
222:             ProcessorDefinitionHelper.prepareSourceLocation(definition.getResource(), definition.getInput());
223:             String source = LoggerHelper.getSourceLocationOnly(definition.getInput());
224:             throw new FailedToCreateRouteException(
225:                     definition.getRouteId(), source, definition.toString(), at, cause);
226:         }
227: 
228:         List<ProcessorDefinition<?>> list = new ArrayList<>(definition.getOutputs());
229:         for (ProcessorDefinition<?> output : list) {
230:             try {
231:                 ProcessorReifier<?> reifier = ProcessorReifier.reifier(route, output);
232: 
233:                 // ensure node has id assigned
234:                 String outputId
235:                         = output.idOrCreate(camelContext.getCamelContextExtension().getContextPlugin(NodeIdFactory.class));
236:                 String eip = reifier.getClass().getSimpleName().replace("Reifier", "");
237:                 StartupStep step = camelContext.getCamelContextExtension().getStartupStepRecorder()
238:                         .beginStep(ProcessorReifier.class, outputId, "Create " + eip + " Processor");
239: 
240:                 reifier.addRoutes();
241: 
242:                 camelContext.getCamelContextExtension().getStartupStepRecorder().endStep(step);
243:             } catch (Exception e) {
244:                 // location on route is stored on input
245:                 String source = LoggerHelper
246:                         .getLineNumberLoggerName(definition.getInput() != null ? definition.getInput().getLocation() : null);
247:                 throw new FailedToCreateRouteException(
248:                         definition.getRouteId(), source, definition.toString(), output.toString(), e);
249:             }
250:         }
251: 
252:         // now lets turn all the event driven consumer processors into a single route
253:         List<Processor> eventDrivenProcessors = route.getEventDrivenProcessors();
254:         if (eventDrivenProcessors.isEmpty()) {
255:             return null;
256:         }
257: 
258:         // Set route properties
259:         Map<String, Object> routeProperties = computeRouteProperties();
260: 
261:         // always use a pipeline even if there are only 1 processor as the pipeline
262:         // handles preparing the response from the exchange in regard to IN vs OUT messages etc
263:         RoutePipeline target = new RoutePipeline(camelContext, eventDrivenProcessors);
264:         target.setRouteId(id);
265: 
266:         // and wrap it in a unit of work so the UoW is on the top, so the entire route will be in the same UoW
267:         InternalProcessor internal = PluginHelper.getInternalProcessorFactory(camelContext)
268:                 .addUnitOfWorkProcessorAdvice(camelContext, target, route);
269: 
270:         // configure route policy
271:         if (definition.getRoutePolicies() != null && !definition.getRoutePolicies().isEmpty()) {
272:             for (RoutePolicy policy : definition.getRoutePolicies()) {
273:                 LOG.debug("RoutePolicy is enabled: {} on route: {}", policy, definition.getId());
274:                 route.getRoutePolicyList().add(policy);
275:             }
276:         }
277:         if (definition.getRoutePolicyRef() != null) {
278:             StringTokenizer policyTokens = new StringTokenizer(definition.getRoutePolicyRef(), ",");
279:             while (policyTokens.hasMoreTokens()) {
280:                 String ref = policyTokens.nextToken().trim();
281:                 RoutePolicy policy = mandatoryLookup(ref, RoutePolicy.class);
282:                 LOG.debug("RoutePolicy is enabled: {} on route: {}", policy, definition.getId());
283:                 route.getRoutePolicyList().add(policy);
284:             }
285:         }
286:         if (camelContext.getRoutePolicyFactories() != null) {
287:             for (RoutePolicyFactory factory : camelContext.getRoutePolicyFactories()) {
288:                 RoutePolicy policy = factory.createRoutePolicy(camelContext, definition.getId(), definition);
289:                 if (policy != null) {
290:                     LOG.debug("RoutePolicy is enabled: {} on route: {}", policy, definition.getId());
291:                     route.getRoutePolicyList().add(policy);
292:                 }
293:             }
294:         }
295:         // and then optionally add route policy processor if a custom policy is set
296:         List<RoutePolicy> routePolicyList = route.getRoutePolicyList();
297:         if (routePolicyList != null && !routePolicyList.isEmpty()) {
298:             for (RoutePolicy policy : routePolicyList) {
299:                 // add policy as service if we have not already done that (eg possible if two routes have the same service)
300:                 // this ensures Camel can control the lifecycle of the policy
301:                 if (!camelContext.hasService(policy)) {
302:                     try {
303:                         // inject route
304:                         if (policy instanceof RouteAware ra) {
305:                             ra.setRoute(route);
306:                         }
307:                         camelContext.addService(policy);
308:                     } catch (Exception e) {
309:                         throw RuntimeCamelException.wrapRuntimeCamelException(e);
310:                     }
311:                 }
312:             }
313: 
314:             internal.addRoutePolicyAdvice(routePolicyList);
315:         }
316: 
317:         // wrap in route inflight processor to track number of inflight exchanges for the route
318:         internal.addRouteInflightRepositoryAdvice(camelContext.getInflightRepository(), route.getRouteId());
319: 
320:         // wrap in JMX instrumentation processor that is used for performance stats
321:         ManagementInterceptStrategy managementInterceptStrategy = route.getManagementInterceptStrategy();
322:         if (managementInterceptStrategy != null) {
323:             internal.addManagementInterceptStrategy(managementInterceptStrategy.createProcessor("route"));
324:         }
325: 
326:         // wrap in route lifecycle
327:         internal.addRouteLifecycleAdvice(camelContext, route, definition);
328: 
329:         // add advices
330:         if (definition.getRestBindingDefinition() != null) {
331:             try {
332:                 // when disabling bean or processor we should also disable rest-dsl binding advice
333:                 boolean disabled
334:                         = "true".equalsIgnoreCase(route.getCamelContext().getGlobalOption(DISABLE_BEAN_OR_PROCESS_PROCESSORS));
335:                 if (!disabled) {
336:                     internal.addAdvice(
337:                             new RestBindingReifier(route, definition.getRestBindingDefinition()).createRestBindingAdvice());
338:                 }
339:             } catch (Exception e) {
340:                 throw RuntimeCamelException.wrapRuntimeCamelException(e);
341:             }
342:         }
343: 
344:         // wrap in contract
345:         if (definition.getInputType() != null || definition.getOutputType() != null) {
346:             Contract contract = new Contract();
347:             if (definition.getInputType() != null) {
348:                 contract.setInputType(parseString(definition.getInputType().getUrn()));
349:                 contract.setValidateInput(parseBoolean(definition.getInputType().getValidate(), false));
350:             }
351:             if (definition.getOutputType() != null) {
352:                 contract.setOutputType(parseString(definition.getOutputType().getUrn()));
353:                 contract.setValidateOutput(parseBoolean(definition.getOutputType().getValidate(), false));
354:             }
355:             internal.addAdvice(new ContractAdvice(contract));
356:             // make sure to enable data type as its in use when using
357:             // input/output types on routes
358:             camelContext.setUseDataType(true);
359:         }
360: 
361:         // wrap with variable
362:         if (variable != null) {
363:             internal.addAdvice(new VariableAdvice(variable));
364:         }
365: 
366:         // and create the route that wraps all of this
367:         route.setProcessor(internal);
368:         route.getProperties().putAll(routeProperties);
369:         route.setStartupOrder(startupOrder);
370:         if (isAutoStartup != null) {
371:             LOG.debug("Using AutoStartup {} on route: {}", isAutoStartup, definition.getId());
372:             route.setAutoStartup(isAutoStartup);
373:         }
374: 
375:         // after the route is created then set the route on the policy processor(s) so we get hold of it
376:         internal.setRouteOnAdvices(route);
377: 
378:         // invoke init on route policy
379:         if (routePolicyList != null && !routePolicyList.isEmpty()) {
380:             for (RoutePolicy policy : routePolicyList) {
381:                 policy.onInit(route);
382:             }
383:         }
384: 
385:         // inject the route error handler for processors that are error handler aware
386:         // this needs to be done here at the end because the route may be transactional and have a transaction error handler
387:         // automatic be configured which some EIPs like Multicast/RecipientList needs to be using for special fine-grained error handling
388:         ErrorHandlerFactory builder = route.getErrorHandlerFactory();
389:         Processor errorHandler = ((ModelCamelContext) camelContext).getModelReifierFactory().createErrorHandler(route,
390:                 builder, null);
391:         prepareErrorHandlerAware(route, errorHandler);
392: 
393:         // only during startup phase
394:         if (camelContext.getStatus().ordinal() < ServiceStatus.Started.ordinal()) {
395:             // okay route has been created from the model, then the model is no longer needed, and we can de-reference
396:             camelContext.getCamelContextExtension().addBootstrap(route::clearRouteModel);
397:         }
398: 
399:         if (definition.getRouteTemplateContext() != null) {
400:             // make route stop beans from the local repository (route templates / kamelets)
401:             Service wrapper = new ServiceSupport() {
402:                 @Override
403:                 protected void doStop() throws Exception {
404:                     close();
405:                 }
406: 
407:                 @Override
408:                 public void close() throws IOException {
409:                     BeanRepository repo = definition.getRouteTemplateContext().getLocalBeanRepository();
410:                     if (repo instanceof Closeable obj) {
411:                         IOHelper.close(obj);
412:                     }
413:                     super.close();
414:                 }
415:             };
416:             route.addService(wrapper, true);
417:         }
418: 
419:         return route;
420:     }
421: 
422:     private void prepareErrorHandlerAware(Route route, Processor errorHandler) {
423:         List<Processor> processors = route.filter("*");
424:         for (Processor p : processors) {
425:             if (p instanceof ErrorHandlerAware errorHandlerAware) {
426:                 errorHandlerAware.setErrorHandler(errorHandler);
427:             }
428:         }
429:     }
430: 
431:     protected Map<String, Object> computeRouteProperties() {
432:         Map<String, Object> routeProperties = new HashMap<>();
433:         routeProperties.put(Route.ID_PROPERTY, definition.getId());
434:         routeProperties.put(Route.CUSTOM_ID_PROPERTY, Boolean.toString(definition.hasCustomIdAssigned()));
435:         routeProperties.put(Route.PARENT_PROPERTY, Integer.toHexString(definition.hashCode()));
436:         routeProperties.put(Route.DESCRIPTION_PROPERTY, definition.getDescriptionText());
437:         routeProperties.put(Route.NOTE_PROPERTY, definition.getNote());
438:         if (definition.getGroup() != null) {
439:             routeProperties.put(Route.GROUP_PROPERTY, definition.getGroup());
440:         }
441:         if (definition.getNodePrefixId() != null) {
442:             routeProperties.put(Route.NODE_PREFIX_ID_PROPERTY, definition.getNodePrefixId());
443:         }
444:         String rest = Boolean.toString(definition.isRest() != null && definition.isRest());
445:         routeProperties.put(Route.REST_PROPERTY, rest);
446:         String template = Boolean.toString(definition.isTemplate() != null && definition.isTemplate());
447:         routeProperties.put(Route.TEMPLATE_PROPERTY, template);
448:         String kamelet = Boolean.toString(definition.isKamelet() != null && definition.isKamelet());
449:         routeProperties.put(Route.KAMELET_PROPERTY, kamelet);
450:         if (definition.getAppliedRouteConfigurationIds() != null) {
451:             routeProperties.put(Route.CONFIGURATION_ID_PROPERTY,
452:                     String.join(",", definition.getAppliedRouteConfigurationIds()));
453:         }
454: 
455:         List<PropertyDefinition> properties = definition.getRouteProperties();
456:         if (properties != null) {
457:             for (PropertyDefinition prop : properties) {
458:                 try {
459:                     final String key = parseString(prop.getKey());
460:                     final String val = parseString(prop.getValue());
461:                     for (String property : RESERVED_PROPERTIES) {
462:                         if (property.equalsIgnoreCase(key)) {
463:                             throw new IllegalArgumentException(
464:                                     "Cannot set route property " + property + " as it is a reserved property");
465:                         }
466:                     }
467:                     routeProperties.put(key, val);
468:                 } catch (Exception e) {
469:                     throw RuntimeCamelException.wrapRuntimeCamelException(e);
470:                 }
471:             }
472:         }
473:         return routeProperties;
474:     }
475: 
476:     /**
477:      * Advice for moving message body into a variable when using variableReceive mode
478:      */
479:     private static class VariableAdvice implements CamelInternalProcessorAdvice<Object> {
480: 
481:         private final String name;
482: 
483:         public VariableAdvice(String name) {
484:             this.name = name;
485:         }
486: 
487:         @Override
488:         public Object before(Exchange exchange) throws Exception {
489:             // move body to variable
490:             ExchangeHelper.setVariableFromMessageBodyAndHeaders(exchange, name, exchange.getMessage());
491:             // remember body
492:             Object body = exchange.getMessage().getBody();
493:             exchange.getMessage().setBody(null);
494:             return body;
495:         }
496: 
497:         @Override
498:         public void after(Exchange exchange, Object data) throws Exception {
499:             // restore body if body has not been changed
