135: public abstract class ProcessorReifier<T extends ProcessorDefinition<?>> extends AbstractReifier {
136: 
137:     /**
138:      * Global option on {@link CamelContext#getGlobalOptions()} that tooling can use to disable all route processors,
139:      * which allows to startup Camel without wiring up and initializing all route EIPs that may use custom processors,
140:      * beans, and other services that may not be available, or is unwanted to be in use; for example to have fast
141:      * startup, and being able to introspect CamelContext and the route models.
142:      */
143:     public static final String DISABLE_ALL_PROCESSORS = "DisableAllProcessors";
144: 
145:     /**
146:      * Global option on {@link CamelContext#getGlobalOptions()} that tooling can use to disable route processors (bean
147:      * and custom process), which allows to startup Camel without wiring up and initializing using custom
148:      * bean/processors, that may not be available, or is unwanted to be in use; for example to have fast startup, and
149:      * being able to introspect CamelContext and the route models.
150:      */
151:     public static final String DISABLE_BEAN_OR_PROCESS_PROCESSORS = "DisableBeanOrProcessProcessors";
152: 
153:     private static final Logger LOG = LoggerFactory.getLogger(ProcessorReifier.class);
154: 
155:     // for custom reifiers
156:     private static final Map<Class<?>, BiFunction<Route, ProcessorDefinition<?>, ProcessorReifier<? extends ProcessorDefinition<?>>>> PROCESSORS
157:             = new HashMap<>(0);
158: 
159:     protected final T definition;
160: 
161:     public ProcessorReifier(Route route, T definition) {
162:         super(route);
163:         this.definition = definition;
164:     }
165: 
166:     public ProcessorReifier(CamelContext camelContext, T definition) {
167:         super(camelContext);
168:         this.definition = definition;
169:     }
170: 
171:     public static void registerReifier(
172:             Class<?> processorClass,
173:             BiFunction<Route, ProcessorDefinition<?>, ProcessorReifier<? extends ProcessorDefinition<?>>> creator) {
174:         if (PROCESSORS.isEmpty()) {
175:             ReifierStrategy.addReifierClearer(ProcessorReifier::clearReifiers);
176:         }
177:         PROCESSORS.put(processorClass, creator);
178:     }
179: 
180:     public static void clearReifiers() {
181:         PROCESSORS.clear();
182:     }
183: 
184:     public static ProcessorReifier<? extends ProcessorDefinition<?>> reifier(Route route, ProcessorDefinition<?> definition) {
185:         ProcessorReifier<? extends ProcessorDefinition<?>> answer = null;
186: 
187:         if (!PROCESSORS.isEmpty()) {
188:             // custom take precedence
189:             BiFunction<Route, ProcessorDefinition<?>, ProcessorReifier<? extends ProcessorDefinition<?>>> reifier
190:                     = PROCESSORS.get(definition.getClass());
191:             if (reifier != null) {
192:                 answer = reifier.apply(route, definition);
193:             }
194:         }
195:         if (answer == null) {
196:             answer = coreReifier(route, definition);
197:         }
198:         if (answer == null) {
199:             throw new IllegalStateException("Unsupported definition: " + definition);
200:         }
201:         return answer;
202:     }
