61: 
62:     private static final Logger LOG = LoggerFactory.getLogger(DefaultChannel.class);
63: 
64:     private Processor errorHandler;
65:     // the next processor (non wrapped)
66:     private Processor nextProcessor;
67:     // the real output to invoke that has been wrapped
68:     private Processor output;
69:     private ManagementInterceptStrategy.InstrumentationProcessor<?> instrumentationProcessor;
70:     private Route route;
71: 
72:     public DefaultChannel(CamelContext camelContext) {
73:         super(camelContext);
74:     }
75: 
76:     @Override
77:     public Processor getOutput() {
78:         // the errorHandler is already decorated with interceptors
79:         // so it contain the entire chain of processors, so we can safely use it directly as output
80:         // if no error handler provided we use the output
81:         // the error handlers, interceptors, etc. woven in at design time
82:         return errorHandler != null ? errorHandler : output;
83:     }
84: 
85:     @Override
86:     public boolean hasNext() {
87:         return nextProcessor != null;
88:     }
89: 
90:     @Override
91:     public List<Processor> next() {
92:         if (!hasNext()) {
93:             return null;
94:         }
95:         List<Processor> answer = new ArrayList<>(1);
96:         answer.add(nextProcessor);
97:         return answer;
98:     }
99: 
100:     public void setOutput(Processor output) {
101:         this.output = output;
102:     }
103: 
104:     @Override
105:     public Processor getNextProcessor() {
106:         return nextProcessor;
107:     }
108: 
109:     @Override
110:     public void setErrorHandler(Processor errorHandler) {
111:         this.errorHandler = errorHandler;
112:     }
113: 
114:     @Override
115:     public Processor getErrorHandler() {
116:         return errorHandler;
117:     }
118: 
119:     @Override
120:     public Route getRoute() {
121:         return route;
122:     }
123: 
124:     @Override
125:     protected void doStart() throws Exception {
126:         // do not call super as we want to be in control here of the lifecycle
127: 
128:         // the output has now been created, so assign the output as the processor
129:         setProcessor(getOutput());
130:         ServiceHelper.startService(errorHandler, output);
131:     }
132: 
133:     @Override
134:     protected void doStop() throws Exception {
135:         // do not call super as we want to be in control here of the lifecycle
136: 
137:         // only stop services if not context scoped (as context scoped is reused by others)
138:         ServiceHelper.stopService(output, errorHandler);
139:     }
140: 
141:     @Override
142:     protected void doShutdown() throws Exception {
143:         // do not call super as we want to be in control here of the lifecycle
144: 
145:         ServiceHelper.stopAndShutdownServices(output, errorHandler);
146:     }
