159:         this.nextProcessor = nextProcessor;
160: 
161:         // init CamelContextAware as early as possible on nextProcessor
162:         CamelContextAware.trySetCamelContext(nextProcessor, camelContext);
163: 
164:         // the definition to wrap should be the fine grained,
165:         // so if a child is set then use it, if not then its the original output used
