180:             final MessageHistoryFactory messageHistoryFactory = camelContext.getMessageHistoryFactory();
181:             if (customDebugger != null) {
182:                 // use custom debugger
183:                 addAdvice(new MessageHistoryAdvice(messageHistoryFactory, targetOutputDef));
