639:     /**
640:      * Wraps the child processor in whatever necessary interceptors and error handlers
641:      */
642:     public Channel wrapProcessor(Processor processor) throws Exception {
643:         // don't double wrap
644:         if (processor instanceof Channel channel) {
645:             return channel;
646:         }
647:         return wrapChannel(processor, null);
