714:     /**
715:      * Wraps the given channel in error handler (if error handler is inherited)
716:      *
717:      * @param  channel             the channel
718:      * @param  inheritErrorHandler whether to inherit error handler
719:      * @throws Exception           can be thrown if failed to create error handler builder
720:      */
721:     private void wrapChannelInErrorHandler(Channel channel, Boolean inheritErrorHandler) throws Exception {
722:         if (inheritErrorHandler == null || inheritErrorHandler) {
723:             LOG.trace("{} is configured to inheritErrorHandler", definition);
724:             Processor output = channel.getOutput();
725:             Processor errorHandler = wrapInErrorHandler(output);
726:             // set error handler on channel
727:             channel.setErrorHandler(errorHandler);
728:         } else {
729:             LOG.debug("{} is configured to not inheritErrorHandler.", definition);
730:         }
731:     }
