56: /**
57:  * Represents the runtime objects for a given route so that it can be stopped independently of other routes
58:  */
59: public class RouteService extends ChildServiceSupport {
60: 
61:     private final CamelContext camelContext;
62:     private final StartupStepRecorder startupStepRecorder;
63:     private final Route route;
