93:     /**
94:      * Gather all the endpoints this route service uses
95:      * <p/>
96:      * This implementation finds the endpoints by searching all the child services for {@link EndpointAware} processors
97:      * which uses an endpoint.
98:      */
99:     public Set<Endpoint> gatherEndpoints() {
100:         Set<Endpoint> answer = new LinkedHashSet<>();
101:         Set<Service> services = gatherChildServices();
102:         for (Service service : services) {
103:             if (service instanceof EndpointAware endpointAware) {
104:                 Endpoint endpoint = endpointAware.getEndpoint();
105:                 if (endpoint != null) {
106:                     answer.add(endpoint);
107:                 }
108:             }
109:         }
110:         return answer;
111:     }
