161:     protected void doSetup() throws Exception {
162:         lock.lock();
163:         try {
164:             // to setup we initialize the services
165:             ServiceHelper.initService(route.getEndpoint());
166: 
167:             try (MDCHelper mdcHelper = new MDCHelper(route.getId())) {
168: 
169:                 // ensure services are initialized first
170:                 route.initializeServices();
171:                 List<Service> services = route.getServices();
172: 
173:                 // split into consumers and child services as we need to start the consumers
174:                 // afterwards to avoid them being active while the others start
175:                 List<Service> list = new ArrayList<>();
176:                 for (Service service : services) {
177: 
178:                     // inject the route
179:                     if (service instanceof RouteAware routeAware) {
180:                         routeAware.setRoute(route);
181:                     }
182:                     if (service instanceof RouteIdAware routeIdAware) {
183:                         routeIdAware.setRouteId(route.getId());
184:                     }
185:                     // inject camel context
186:                     CamelContextAware.trySetCamelContext(service, camelContext);
187: 
188:                     if (service instanceof Consumer consumer) {
189:                         this.input = consumer;
190:                     } else {
191:                         list.add(service);
192:                     }
193:                 }
194:                 initChildServices(list);
195:             }
196:         } finally {
197:             lock.unlock();
198:         }
199:     }
200: 
201:     protected void doWarmUp() throws Exception {
202:         lock.lock();
203:         try {
204:             if (endpointDone.compareAndSet(false, true)) {
205:                 // endpoints should only be started once as they can be reused on other routes
206:                 // and whatnot, thus their lifecycle is to start once, and only to stop when Camel shutdown
207:                 // ensure endpoint is started first (before the route services, such as the consumer)
208:                 ServiceHelper.startService(route.getEndpoint());
209:             }
210: 
211:             if (warmUpDone.compareAndSet(false, true)) {
212: 
213:                 try (MDCHelper mdcHelper = new MDCHelper(route.getId())) {
214:                     // warm up the route first
215:                     route.warmUp();
216: 
217:                     startChildServices(route, childServices);
218: 
219:                     // fire event
220:                     EventHelper.notifyRouteAdded(camelContext, route);
221:                 }
222: 
223:                 // ensure lifecycle strategy is invoked which among others enlist the route in JMX
224:                 for (LifecycleStrategy strategy : camelContext.getLifecycleStrategies()) {
225:                     strategy.onRoutesAdd(Collections.singletonList(route));
226:                 }
227: 
228:                 // add routes to camel context
229:                 camelContext.getCamelContextExtension().addRoute(route);
230: 
231:                 // add the routes to the inflight registry so they are pre-installed
232:                 camelContext.getInflightRepository().addRoute(route.getId());
233:             }
234:         } finally {
235:             lock.unlock();
236:         }
237:     }
