239:     @Override
240:     protected void doStart() {
241:         try (MDCHelper mdcHelper = new MDCHelper(route.getId())) {
242:             // fire event
243:             EventHelper.notifyRouteStarting(camelContext, route);
244:         }
245: 
246:         // ensure we are warmed up
247:         warmUp();
248: 
249:         try (MDCHelper mdcHelper = new MDCHelper(route.getId())) {
250:             // start the route itself
251:             ServiceHelper.startService(route);
252: 
253:             // invoke callbacks on route policy
254:             routePolicyCallback(RoutePolicy::onStart);
255: 
256:             // fire event
257:             EventHelper.notifyRouteStarted(camelContext, route);
258:         }
259:     }
260: 
261:     @Override
262:     protected void doStop() {
263:         try (MDCHelper mdcHelper = new MDCHelper(route.getId())) {
264:             // fire event
265:             EventHelper.notifyRouteStopping(camelContext, route);
266:         }
267: 
268:         // if we are stopping CamelContext then we are shutting down
269:         boolean isShutdownCamelContext = camelContext.isStopping();
270: 
271:         if (isShutdownCamelContext || isRemovingRoutes()) {
272:             // need to call onRoutesRemove when the CamelContext is shutting down or Route is shutdown
273:             for (LifecycleStrategy strategy : camelContext.getLifecycleStrategies()) {
274:                 strategy.onRoutesRemove(Collections.singletonList(route));
275:             }
276:         }
277: 
278:         try (MDCHelper mdcHelper = new MDCHelper(route.getId())) {
279:             // gather list of services to stop
280:             Set<Service> services = gatherChildServices();
281: 
282:             // stop services
283:             stopChildServices(route, services, isShutdownCamelContext);
284: 
285:             // stop the route itself
286:             if (isShutdownCamelContext) {
287:                 ServiceHelper.stopAndShutdownServices(route);
288:             } else {
289:                 ServiceHelper.stopService(route);
290:             }
291: 
292:             // invoke callbacks on route policy
293:             routePolicyCallback(RoutePolicy::onStop);
294: 
295:             // fire event
296:             EventHelper.notifyRouteStopped(camelContext, route);
297:         }
298:         if (isRemovingRoutes()) {
299:             camelContext.getCamelContextExtension().removeRoute(route);
300:         }
